INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Model library API$q$, $q$Access thousands of pre-hosted open-source models for image, video, audio, and text generation through a single consistent REST API.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Cog packaging$q$, $q$Open-source tool for containerizing custom ML models so they run reliably on Replicate's infrastructure with reproducible versioning.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Per-second usage billing$q$, $q$No subscription fees — pay only for the CPU or GPU seconds a prediction actually consumes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Custom model deployment$q$, $q$Push and host your own fine-tuned or proprietary models alongside community models.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Fine-tuning support$q$, $q$Train and fine-tune select model families (e.g., image and language models) directly on the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Webhooks and async predictions$q$, $q$Long-running predictions can notify your application via webhook instead of blocking on a synchronous API call.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Private deployments$q$, $q$Reserve dedicated hardware for a specific model to guarantee latency and availability for production workloads.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Multi-GPU configurations$q$, $q$Scale predictions across multiple H100 or A100 GPUs for large or latency-sensitive workloads.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$No subscription required — pay only for actual compute used$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Very large and constantly updated catalog of open-source models$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Cog makes packaging and deploying custom models straightforward$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Transparent, publicly listed per-second GPU pricing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Backed by Cloudflare's infrastructure following the 2025 acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Costs can scale unpredictably with heavy or bursty usage since there is no flat plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Private models and deployments bill for idle time, not just active processing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Cold starts can add latency for infrequently used models$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Enterprise-scale committed-spend pricing is not publicly listed and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Some advanced model categories use less-transparent token or output-based pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$What is Replicate used for?$q$, $q$Replicate lets developers run and deploy open-source machine learning models, such as image generators, video generators, speech models, and large language models, through a simple API without managing their own GPU servers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$How does Replicate pricing work?$q$, $q$Replicate has no monthly subscription. Customers pay per second of compute used, with rates starting around $0.000025/sec for CPU and going up to about $0.001525/sec for a single Nvidia H100 GPU; some models bill per token or per output unit instead.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Who founded Replicate and when?$q$, $q$Replicate was founded in 2019 by Ben Firshman and Andreas Jansson, and is headquartered in San Francisco, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Is Replicate still an independent company?$q$, $q$No. Cloudflare announced its acquisition of Replicate in November 2025, and the deal closed in December 2025. Replicate continues to operate under its own brand within Cloudflare.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$What is Cog?$q$, $q$Cog is Replicate's open-source tool for packaging machine learning models and their dependencies into standard containers that can be deployed and versioned on Replicate's infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Does Replicate offer a free tier?$q$, $q$Replicate does not advertise a dedicated free subscription tier; new accounts typically pay as they go for compute used, and enterprise customers can negotiate committed-spend contracts.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Can I deploy my own custom model on Replicate?$q$, $q$Yes. Developers can package a custom or fine-tuned model with Cog and push it to Replicate, where it can be served through the same API used for community models.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Does Replicate support fine-tuning?$q$, $q$Yes, Replicate supports fine-tuning for select model families, allowing users to train models on their own data before deploying them.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$AI product prototyping$q$, $q$Startups and indie developers use Replicate to test generative AI features like image or video generation in a product without provisioning GPU infrastructure.$q$, $q$Startup engineering teams and indie developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Variable-traffic production inference$q$, $q$Teams with unpredictable or bursty inference traffic use Replicate's per-second billing to avoid paying for idle reserved GPU capacity.$q$, $q$AI product teams with fluctuating usage$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Custom model hosting$q$, $q$Teams that fine-tune their own models use Cog to package and deploy them on Replicate's managed hardware for API access.$q$, $q$ML engineers and researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Pay-as-you-go$q$, $q$From $0.000025/sec$q$, $q$usage-based$q$, NULL, $q$["No monthly subscription fee","CPU pricing from $0.000025/sec","Nvidia T4 GPU at $0.000225/sec","Nvidia L40S GPU at $0.000975/sec","Nvidia A100 80GB at $0.001400/sec","Nvidia H100 GPU at $0.001525/sec","Billed only for active processing time on public models"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$Enterprise / Committed Spend$q$, $q$Custom$q$, $q$contract$q$, NULL, $q$["Volume discounts for committed usage","Dedicated multi-GPU A100/H100 capacity","Private deployments and reserved hardware","Custom support arrangements"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Replicate is an AI infrastructure company that hosts thousands of open-source machine learning models and exposes them through a unified API, so developers can generate images, video, speech, and text without setting up their own GPU servers. Founded in 2019 by Ben Firshman and Andreas Jansson and based in San Francisco, the company built its reputation on Cog, an open-source packaging tool that lets any model be containerized and deployed to Replicate's infrastructure with predictable versioning.$q$, $q$In November 2025, Cloudflare announced an agreement to acquire Replicate in order to integrate its catalog of 50,000+ AI models into the Cloudflare Workers AI platform; the acquisition closed in December 2025. Replicate continues to run as its own product and brand within Cloudflare as of mid-2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Replicate's core feature is one-line API access to a large catalog of community and proprietary open-source models spanning image generation, video generation, audio/speech, upscaling, and large language models, with each model versioned so outputs stay reproducible over time. Developers who want to deploy their own custom model can use Cog to package code and dependencies into a standard container that Replicate can serve automatically on the appropriate GPU hardware.$q$, $q$Additional platform capabilities include webhooks for asynchronous predictions, fine-tuning support for select model families, private deployments with dedicated hardware, and an official Python and Node.js SDK for integrating predictions directly into application code.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60180cba-c779-4a42-9314-22aade49a3a1', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Replicate has no monthly subscription; every account pays strictly for the compute it consumes, billed per second of hardware time. CPU instances start at roughly $0.000025/sec, while GPU rates range from about $0.000225/sec for an Nvidia T4 up to $0.001525/sec for a single Nvidia H100, with multi-GPU configurations priced proportionally higher.$q$, $q$Public community models bill only for active prediction time, while private models and standing deployments also bill for idle and setup time since the hardware stays reserved. Certain high-traffic model categories, especially large language models and generative media models, instead bill per token or per second/frame of output. Organizations with large or predictable workloads can negotiate custom enterprise pricing with volume discounts and committed-spend contracts.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Replit Agent$q$, $q$AI system that plans, writes, tests, and deploys full applications from natural-language prompts, including database and backend provisioning.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Cloud IDE$q$, $q$Browser-based development environment supporting dozens of languages with no local installation required.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Real-time multiplayer collaboration$q$, $q$Multiple users can edit and run the same project simultaneously, similar to collaborative document editing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Built-in database and hosting$q$, $q$Full-stack apps get an integrated database and one-click deployment without separate infrastructure setup.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Parallel AI agents$q$, $q$Higher-tier plans allow running multiple Agent sessions in parallel to build or modify different parts of a project simultaneously.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Deployment privacy controls$q$, $q$Publish apps as public, private, or password-protected, with custom domains available on paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Database rollbacks$q$, $q$Pro plan supports rolling back the database up to 28 days, useful for recovering from AI-driven changes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Enterprise security controls$q$, $q$SSO/SAML, single-tenant environments, and VPC peering available on the custom Enterprise plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$AI Agent can generate and deploy working applications from plain-language prompts$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$No local setup required — fully browser-based development and hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Real-time collaboration makes it useful for pair programming and teaching$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Built-in database and deployment remove the need for separate infrastructure$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Rapid growth and heavy funding suggest strong ongoing product investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Usage-credit model means real costs can exceed the advertised subscription price$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Enterprise pricing is no longer public and requires a sales conversation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$AI-generated code and database changes can require careful review before production use$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Parallel agent and collaborator limits are capped by plan tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Frequent pricing and plan restructuring (e.g., Teams retirement) can make cost planning harder$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$What is Replit used for?$q$, $q$Replit is a browser-based platform for writing, running, and deploying code, and increasingly for building full applications using its AI coding agent, Replit Agent, from natural-language prompts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$How much does Replit cost?$q$, $q$Replit has a free Starter plan, a Core plan at $20/month billed annually ($25 monthly), a Pro plan at $95/month billed annually ($100 monthly), and a custom-priced Enterprise plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$What happened to Replit's Teams plan?$q$, $q$Replit retired its Teams plan in February 2026 and replaced it with a new Pro plan that includes more collaborators, parallel agents, and access to more capable AI models.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Who founded Replit?$q$, $q$Replit was founded in 2016 by Amjad Masad, Haya Odeh, and Faris Masad.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Where is Replit headquartered?$q$, $q$Replit is headquartered at 1001 East Hillsdale Boulevard in Foster City, California, after relocating from San Francisco in 2024.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$What is Replit Agent?$q$, $q$Replit Agent is Replit's AI system that can plan, write, test, and deploy software, including provisioning databases and backend logic, from a natural-language description.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$How much funding has Replit raised?$q$, $q$Replit has raised approximately $922 million in total funding, including a $400 million Series D in March 2026 at a $9 billion valuation.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Do usage credits expire on Replit?$q$, $q$Yes, monthly usage credits included with Core and Pro plans generally expire if unused within a set period, so actual usage patterns affect total cost.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$AI-assisted app building$q$, $q$Non-technical founders and product teams use Replit Agent to generate and deploy working web applications from natural-language prompts.$q$, $q$Non-technical founders and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Learning to code$q$, $q$Students and hobbyists use Replit's free, zero-setup browser IDE to write and run code in dozens of languages without installing anything locally.$q$, $q$Students and self-taught developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Collaborative development and prototyping$q$, $q$Engineering teams use Replit's real-time multiplayer editing and instant deployment to prototype and pair-program on projects together.$q$, $q$Software engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Starter$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Limited daily Agent credits","Built-in database for full-stack apps","Publish up to 1 project","Private or password-protected deployments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Core$q$, $q$$20/month (billed annually) or $25/month$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Starter","$25 of monthly usage credits","Up to 5 collaborators","Up to 2 parallel AI agents","Unlimited workspaces","Removes 'Made with Replit' badge"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Pro$q$, $q$$95/month (billed annually) or $100/month$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Core","$100 of monthly usage credits","Up to 15 collaborators and 50 viewers","Up to 10 parallel AI agents","Access to the most powerful AI models","Database rollbacks for up to 28 days","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["All Pro features","Custom seat limits","SSO/SAML","Single-tenant environments and VPC peering","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Replit began in 2016 as a browser-based IDE that let developers code, run, and share projects instantly without local setup, and has since evolved into an AI-first app-building platform centered on Replit Agent, which can generate, debug, and deploy full applications from natural-language instructions. Co-founded by Amjad Masad, Haya Odeh, and Faris Masad, the company is now headquartered in Foster City, California.$q$, $q$Fueled by a $400 million Series D in March 2026 at a $9 billion valuation, Replit has grown rapidly on the back of AI-assisted software creation, positioning itself for both individual developers and enterprise teams building internal tools and customer-facing apps.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Replit's core is a cloud development environment accessible from any browser, supporting dozens of programming languages with zero local setup, real-time multiplayer editing, and one-click hosting and deployment for web apps. Its most differentiated feature is Replit Agent, an AI system capable of planning, writing, testing, and iterating on full applications, including provisioning a built-in Postgres-backed database, from a natural-language prompt.$q$, $q$Collaboration tools include shared workspaces with configurable collaborator and viewer limits, deployment privacy controls (public, private, or password-protected), and database rollback features on higher tiers for recovering from AI-driven mistakes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c628f71b-c0ff-42aa-87ea-a09dfbd28490', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Replit offers four tiers. Starter is free and includes limited daily Agent credits, a built-in database, and the ability to publish one project. Core costs $20/month billed annually (or $25/month billed monthly) and adds $25 in monthly usage credits, up to five collaborators, two parallel AI agents, unlimited workspaces, and removal of the 'Made with Replit' badge.$q$, $q$Pro, introduced in February 2026 to replace the former Teams plan, costs $95/month billed annually (or $100/month billed monthly) and includes $100 in monthly credits, up to 15 collaborators and 50 viewers, ten parallel agents, access to the most capable AI models, and 28-day database rollbacks. Enterprise pricing is custom and adds SSO/SAML, single-tenant environments, VPC peering, and dedicated support; Replit has removed public enterprise pricing from its website in favor of a sales-led process.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Automated cross-platform publishing$q$, $q$New content from a source platform is automatically pulled and republished across 15+ destination platforms without manual re-uploading.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Auto-resizing and reformatting$q$, $q$Video is automatically resized and reformatted to fit each destination platform's required aspect ratio and specs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Watermark removal$q$, $q$Removes source-platform watermarks (e.g., TikTok watermark) before republishing to other channels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Podcast-to-video repurposing$q$, $q$Converts podcast audio episodes into short video clips suitable for social distribution.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Official platform partnerships$q$, $q$Approved API integrations with Meta, YouTube, TikTok, Snapchat, and Amazon reduce the risk of account flagging.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Stories repurposing$q$, $q$Supports automated repurposing into Stories format, a capability the company says few direct competitors offer.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Multi-account support$q$, $q$Connect multiple accounts per social network, with limits scaling by plan tier from 3 to 25 accounts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Scheduled or real-time workflows$q$, $q$Configure workflows to publish content automatically as soon as it's detected or on a set schedule.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Fully automated 'set it and forget it' workflows save significant manual repurposing time$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Official partnerships with major platforms reduce compliance and account-flagging risk$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Supports a wide range of destination platforms, including less-common ones like BlueSky and Twitch$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Stories repurposing is a differentiator versus many competitors$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$14-day free trial and 10 free video publishes let users test before paying$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Starter plan caps published videos at 5,000/month and limits accounts per network to 3$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Pricing can become expensive for agencies needing the top Agency tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Focused specifically on repurposing existing content, not original content creation or general scheduling$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Small company size (under 15 employees) may limit support responsiveness at scale$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Some advanced destination-specific formatting nuances may still require manual review$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$What does Repurpose.io do?$q$, $q$Repurpose.io automatically pulls video, Reels, Shorts, Stories, or podcast content from a source platform and republishes it, resized and reformatted, across 15+ destination platforms like TikTok, Instagram, YouTube Shorts, and Facebook.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$How much does Repurpose.io cost?$q$, $q$Repurpose.io has three plans: Starter at $35/month, Pro at $79/month, and Agency at $179/month, with roughly 17% savings available on annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Who founded Repurpose.io?$q$, $q$Repurpose.io was founded in November 2016 by Hani Mourra and is based in Austin, Texas.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Does Repurpose.io offer a free trial?$q$, $q$Yes, all plans include a 14-day free trial, and new users can also try the platform with 10 free video publishes before subscribing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Which platforms does Repurpose.io support?$q$, $q$Repurpose.io supports TikTok, YouTube Shorts, Instagram, Facebook, Pinterest, LinkedIn, X, Amazon, BlueSky, and Twitch, among other destinations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Is Repurpose.io an official partner of social platforms?$q$, $q$Yes, the company states it is an official platform partner of Meta, YouTube, TikTok, Snapchat, and Amazon.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$What is the difference between the Starter, Pro, and Agency plans?$q$, $q$The plans differ mainly in the number of connected accounts per social network (3, 10, or 25) and monthly video publishing limits (5,000 on Starter versus unlimited on Pro and Agency).$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Can Repurpose.io remove TikTok watermarks?$q$, $q$Yes, the platform automatically removes source-platform watermarks, such as TikTok's, before republishing content to other channels.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Solo creator content multiplication$q$, $q$Solo content creators use Repurpose.io to automatically turn one TikTok or YouTube Short into posts across multiple other platforms without manual re-editing.$q$, $q$Solo content creators and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Podcast clip distribution$q$, $q$Podcasters use the platform to automatically convert new episodes into short video clips distributed across social media to drive show discovery.$q$, $q$Podcasters and audio creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Agency multi-client management$q$, $q$Social media agencies use the Agency plan to automate content repurposing workflows across many client accounts and social networks simultaneously.$q$, $q$Social media agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Starter$q$, $q$$35/month or $349/year$q$, $q$monthly or annual$q$, NULL, $q$["Up to 3 accounts per social network","5,000 published videos per month","Automated cross-platform repurposing","14-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Pro$q$, $q$$79/month or $790/year$q$, $q$monthly or annual$q$, NULL, $q$["Up to 10 accounts per social network","Unlimited published videos","Automated cross-platform repurposing","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$Agency$q$, $q$$179/month or $1,790/year$q$, $q$monthly or annual$q$, NULL, $q$["Up to 25 accounts per social network","Unlimited published videos","Automated cross-platform repurposing","14-day free trial"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Repurpose.io was founded in November 2016 by Hani Mourra and is based in Austin, Texas. The platform automates the process of taking a single piece of video, Reel, Short, Story, or podcast content and republishing it, correctly resized and formatted, across more than 15 social and content platforms without manual re-uploading.$q$, $q$The company positions itself as an official platform partner of Meta, YouTube, TikTok, Snapchat, and Amazon, which it says allows its automation to run through approved APIs rather than risky workarounds, reducing the chance of accounts being flagged or automation breaking when platforms update their systems.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Repurpose.io's central feature is workflow-based automation: a creator connects a source account (for example TikTok or a podcast RSS feed) and one or more destination accounts, and every new piece of content is automatically pulled, reformatted for each destination's aspect ratio and requirements, watermark-removed where applicable, and published on a schedule or in near real time.$q$, $q$The platform supports distribution to TikTok, YouTube Shorts, Instagram (including Reels and Stories), Facebook, Pinterest, LinkedIn, X, Amazon, BlueSky, and Twitch, and includes tools for converting podcast audio into short video clips for social distribution.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f07f9c22-d47c-4952-97ad-64f962870184', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Repurpose.io offers three monthly subscription tiers, each with a discounted annual option. Starter is $35/month ($349/year) with up to 3 connected accounts per network and 5,000 published videos monthly; Pro is $79/month ($790/year) with up to 10 accounts per network and unlimited published videos; and Agency is $179/month ($1,790/year) with up to 25 accounts per network and unlimited publishing.$q$, $q$Annual billing saves roughly 17% compared to paying monthly. All plans include a 14-day free trial, and prospective users can try the platform with 10 free video publishes before committing to a paid subscription.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Multi-location review monitoring$q$, $q$Aggregates and tracks online reviews across every business location from a single centralized dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Review response management$q$, $q$Tools to respond to customer reviews at scale, including templated and AI-assisted responses.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Customer survey collection$q$, $q$Built-in survey tools to gather structured customer feedback alongside organic review data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Social listening$q$, $q$Monitors social media mentions and sentiment relevant to the brand and its individual locations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Business listings management$q$, $q$Keeps local business listings (name, address, phone, hours) accurate and consistent across directories.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Location-level benchmarking$q$, $q$Compares reputation metrics across a brand's own locations and against competitors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$AI search visibility tracking$q$, $q$Monitors how a brand is represented within AI-generated search and chatbot answers, not just traditional search results.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Role-based enterprise access$q$, $q$Supports complex multi-brand or franchise organizational structures with tailored user permissions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Purpose-built for large multi-location enterprises with complex reputation needs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Combines reviews, surveys, social listening, and listings management in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Increasingly tracks AI-driven search and chatbot visibility, not just traditional SEO$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Long operating history (founded 2006) with substantial enterprise customer base$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Backed by significant funding and private equity investment, suggesting platform stability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$No public pricing — requires a sales-led custom quote process$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$No free trial available for prospective customers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Enterprise-oriented pricing (potentially thousands of dollars per month) may be out of reach for small businesses$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Best suited to organizations with 10+ locations, limiting fit for single-location businesses$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Complex feature set may require onboarding investment to use effectively$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$What does Reputation.com do?$q$, $q$Reputation.com is an enterprise reputation and customer experience management platform that helps multi-location businesses monitor and manage online reviews, surveys, social listening, and search/AI visibility across all their locations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$How much does Reputation.com cost?$q$, $q$Reputation.com does not publish standard pricing. While some sources cite an entry point around $80/month, most enterprise deployments cost from several thousand to over $20,000 per month depending on locations, modules, and contract terms.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Who founded Reputation.com and when?$q$, $q$Reputation.com was founded in 2006 by Michael Fertik and Brian Kelley, originally as ReputationDefender, before pivoting to an enterprise B2B model around 2011.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Where is Reputation.com headquartered?$q$, $q$Reputation.com is headquartered in San Ramon, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Does Reputation.com offer a free trial?$q$, $q$No, Reputation.com does not offer a publicly available free trial; pricing and access are handled through a custom sales process.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Who is Reputation.com designed for?$q$, $q$Reputation.com primarily serves enterprise organizations with 10 or more locations, such as healthcare systems, automotive dealership groups, restaurant chains, and retail networks.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Does Reputation.com help with AI search visibility?$q$, $q$Yes, the platform has expanded to help brands monitor and improve how they appear in AI-generated search and chatbot answers, in addition to traditional search engine results.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$How much funding has Reputation.com raised?$q$, $q$Reputation.com has raised approximately $325.3 million in total funding, with a $150 million investment from Marlin Equity Partners in January 2022 valuing the company at roughly $730 million.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Multi-location review management$q$, $q$Auto dealer groups and retail chains use Reputation.com to monitor and respond to reviews across dozens or hundreds of individual locations from one dashboard.$q$, $q$Multi-location retail and automotive brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Healthcare system reputation monitoring$q$, $q$Healthcare systems use the platform to track patient feedback and reviews across many facilities and providers while maintaining compliance-conscious response workflows.$q$, $q$Healthcare systems and provider networks$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Franchise brand consistency$q$, $q$Franchise organizations use location-level benchmarking and role-based access to keep reputation management consistent across independently operated franchise locations.$q$, $q$Franchise and multi-brand enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Core (entry-level)$q$, $q$From approximately $80/month (varies by source)$q$, $q$monthly or annual (custom)$q$, NULL, $q$["Review monitoring","Basic listings management","Limited location coverage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$Enterprise (Custom)$q$, $q$Custom quote (typically several thousand to $20,000+/month)$q$, $q$annual contract$q$, NULL, $q$["Multi-location review and survey management","Social listening","AI search visibility tracking","Business listings management","Role-based enterprise access","Dedicated account support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Reputation was founded in 2006 by Michael Fertik and Brian Kelley, originally as ReputationDefender, a consumer-focused online reputation service, before shifting to an enterprise B2B model around 2011. The company is now headquartered in San Ramon, California, and markets itself as an AI-native reputation management platform for multi-location businesses.$q$, $q$Reputation.com has raised roughly $325.3 million in funding over its history, with its most recent disclosed valuation around $730 million following a $150 million investment led by Marlin Equity Partners in January 2022. The company reports around 693 employees as of 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform centralizes review monitoring and response, customer survey collection, social listening, and local business listing management across every location a brand operates, giving multi-location businesses a single dashboard to track reputation at scale. It increasingly includes tools focused on how a brand is represented in AI-generated search and chatbot answers, alongside traditional search-engine visibility.$q$, $q$Reputation.com is designed for enterprise customers with complex organizational structures, offering location-level benchmarking, competitive analysis, and role-based access so franchise or multi-brand organizations can manage reputation consistently across dozens or hundreds of locations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69e9043e-430d-4fc5-97c8-fc58de34946f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Reputation.com does not publish standard tiered pricing; the platform is sold through a custom enterprise sales process, with quotes based on the number of locations and brands managed, which modules are licensed, data volume, customization needs, user seat count, and contract length.$q$, $q$While some third-party sources cite an entry-level price point around $80/month, most enterprise deployments — particularly for organizations with 10 or more locations — range from several thousand to upwards of $20,000 per month. There is no publicly advertised free trial; prospective customers work with the sales team to scope and price a deployment.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Email-integrated ticketing$q$, $q$Create and update tickets directly via email, allowing requesters to interact without needing a portal login.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Visual Lifecycle builder$q$, $q$Customize ticket states and workflows visually to match an organization's internal processes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Scrips and Actions automation$q$, $q$Rules-based automation engine that triggers actions or notifications based on ticket events.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Built-in knowledge base$q$, $q$Articles feature for storing FAQs and canned responses accessible to agents and, optionally, requesters.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Asset management$q$, $q$Track equipment and configuration items associated with tickets for IT operations use cases.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$SLA management$q$, $q$Business-hours-aware SLA tracking to monitor response and resolution time commitments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$REST v2 API and Zapier integration$q$, $q$Programmatic access and no-code automation connections to other tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Role-based security$q$, $q$Granular permissions and access controls suited to complex organizational structures.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Core software is free and open source with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Over 25 years of active development and a mature, stable codebase$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Highly customizable workflows via Lifecycle builder and Scrips automation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Large ecosystem of 400+ free community extensions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Both self-hosted and managed Cloud RT deployment options available$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Self-hosting requires technical expertise to install, configure, and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$User interface is less modern-looking than many newer SaaS helpdesk tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Best Practical Solutions is a small company (roughly 9-11 employees), which may limit support capacity$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Managed Cloud RT and support pricing is not fully transparent on the primary site$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Steeper learning curve than simpler out-of-the-box helpdesk tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Is Request Tracker free?$q$, $q$Yes, the core Request Tracker software is free and open source under the GNU General Public License for self-hosted use. Best Practical Solutions also offers paid hosted Cloud RT and support packages.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Who created Request Tracker?$q$, $q$Request Tracker was first released in 1996 by Jesse Vincent, who later founded Best Practical Solutions LLC to develop and support it commercially.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Who maintains Request Tracker today?$q$, $q$Best Practical Solutions LLC, a small company headquartered in Somerville, Massachusetts, maintains and supports Request Tracker.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$What is RTIR?$q$, $q$RT for Incident Response (RTIR) is a specialized variant of Request Tracker designed for security teams handling incident-response ticketing workflows.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Can Request Tracker be self-hosted?$q$, $q$Yes, RT can be downloaded and self-hosted for free, or run through Best Practical's hosted Cloud RT service for organizations that prefer a managed deployment.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Does Request Tracker support automation?$q$, $q$Yes, RT includes an automation engine called Scrips and Actions that triggers rules-based responses and notifications based on ticket events.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$What languages does Request Tracker support?$q$, $q$RT's interface supports more than 35 languages through community translations.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Does Request Tracker have an API?$q$, $q$Yes, RT includes a REST v2 API and supports Zapier integration for connecting to other tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$IT help desk ticketing$q$, $q$IT teams use Request Tracker to log, route, and resolve internal support requests with SLA tracking and asset management.$q$, $q$IT support and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Security incident response$q$, $q$Security teams use the RTIR variant to track and manage incident-response tickets through a structured workflow.$q$, $q$Security operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Self-hosted customer support$q$, $q$Organizations that require full data control and no vendor lock-in self-host RT for customer-facing support ticketing.$q$, $q$Organizations with data-sovereignty or compliance requirements$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full source code access under GNU GPL","Self-managed installation and hosting","400+ free community extensions","No per-user licensing fee"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$Cloud RT and Support (Best Practical)$q$, $q$Custom, third-party trackers cite roughly $25-$105/user/month across tiers$q$, $q$monthly or annual$q$, NULL, $q$["Hosted Cloud RT deployment","Training and onboarding","Support and consulting services","Tiered storage and feature levels"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Request Tracker (RT) is one of the longest-running open-source ticketing systems in active use, first released in 1996 by Jesse Vincent and now developed and supported by Best Practical Solutions LLC, a small company based in Somerville, Massachusetts. RT is distributed under the GNU General Public License, meaning organizations can self-host it for free and modify the source code, which is maintained publicly on GitHub.$q$, $q$Best Practical Solutions also offers a hosted Cloud RT service along with training, consulting, and support packages for organizations that want RT's flexibility without managing their own servers. A specialized edition, RT for Incident Response (RTIR), targets security teams handling incident-response workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$RT provides email-based ticket creation and updates, a visual Lifecycle builder for customizing ticket states and workflows, an automation engine (Scrips and Actions) for rules-based ticket handling, a knowledge base for FAQs and canned responses, asset management, SLA tracking with business-hours support, and role-based permissions.$q$, $q$Integration options include a REST v2 API and Zapier connectivity, and the platform supports a multi-language interface covering more than 35 languages. More than 400 community-built extensions are freely available to extend RT's core functionality.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c74c6d31-a2de-408d-9658-1ce6cd0f1ff3', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Request Tracker software is free and open source to download and self-host under the GNU General Public License, with no licensing fee required. Organizations that prefer a managed option can subscribe to Best Practical's hosted Cloud RT service or purchase support, training, and consulting packages.$q$, $q$Third-party pricing trackers cite tiered monthly per-user pricing for RT-related services (roughly $25 to $105 per user/month across Starter, Business, Growth, and Enterprise tiers), which reflects Best Practical's Cloud RT hosting and support offerings rather than a fee for the open-source software itself.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Cataloguing and acquisitions$q$, $q$Manages the full lifecycle of library materials from acquisition through cataloguing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Circulation and lending$q$, $q$Handles checkouts, returns, holds, and other lending operations for library patrons.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Public discovery interface$q$, $q$Provides a public-facing search and browse interface for library users.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Multi-library network support$q$, $q$Supports both independent libraries and consortial library networks sharing a single system instance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Built on Invenio (CERN)$q$, $q$Uses the Invenio digital library framework, originally developed at CERN, as its technical foundation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Multilingual interface$q$, $q$Available in French, German, Italian, and English to serve Switzerland's multilingual library sector.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Open-source and community-driven$q$, $q$Source code is publicly available on GitHub, with community contributions welcomed via chat channels.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Public test instance$q$, $q$Institutions can evaluate the system on a public test deployment before migrating.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Free and open source with no license fee required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Built on the CERN-developed Invenio framework, a mature research-grade technology base$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Purpose-built for library-specific workflows like cataloguing and circulation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Multilingual interface suited to Switzerland's French, German, and Italian-speaking regions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Supports both single-library and multi-library consortium deployments$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Niche, sector-specific tool with limited relevance outside libraries and archives$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Primarily adopted in Switzerland, with less documented international deployment$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Self-hosting requires technical resources; managed hosting terms are not publicly published$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Smaller ecosystem and community compared to major proprietary ILS vendors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Governed by a foundation model that may move more slowly than commercial software vendors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$What is RERO ILS?$q$, $q$RERO ILS is a free, open-source integrated library system for managing acquisitions, cataloguing, circulation, and public discovery, built on the CERN-developed Invenio framework.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Who developed RERO ILS?$q$, $q$RERO ILS was developed starting in 2017 by RERO, in collaboration with the Catholic University of Louvain in Belgium, and is now governed by the RERO+ foundation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Is RERO ILS free to use?$q$, $q$Yes, RERO ILS is open source and free to download and self-host; managed hosting or support arrangements are negotiated separately with RERO+.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Who uses RERO ILS?$q$, $q$RERO ILS is used primarily by public, school, and heritage libraries and library networks in Switzerland, with interest from other libraries internationally.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$What framework is RERO ILS built on?$q$, $q$RERO ILS is built on Invenio, a digital library software framework originally developed at CERN.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$When did RERO ILS launch in production?$q$, $q$RERO ILS reached its first major release (v1.0.0) at the end of 2020, with the first real-world production library instance going live in June 2021.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$What languages does RERO ILS support?$q$, $q$RERO ILS's interface is available in French, German, Italian, and English.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$What organization governs RERO ILS today?$q$, $q$RERO+, a foundation of private law and public interest established in April 2021 by the Swiss cantons of Jura, Neuchatel, and Valais and the city of Martigny, governs RERO ILS.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Public library system management$q$, $q$Public libraries use RERO ILS to manage cataloguing, circulation, and public discovery for their collections.$q$, $q$Public library systems$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Library network consortia$q$, $q$Groups of libraries sharing resources use RERO ILS's multi-library support to operate a shared catalog and circulation system across institutions.$q$, $q$Library consortia and networks$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$School and heritage library cataloguing$q$, $q$School and heritage libraries use RERO ILS as a free, open-source alternative to proprietary library management software.$q$, $q$School and heritage libraries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full source code access","Self-managed installation and hosting","Community support via GitHub and chat channels","Public test instance for evaluation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$Managed Implementation (RERO+)$q$, $q$Custom (contact RERO+)$q$, $q$negotiated$q$, NULL, $q$["Migration assistance","Managed hosting","Technical support","Multilingual configuration"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RERO ILS is an open-source integrated library system developed starting in 2017 by RERO, in collaboration with the Catholic University of Louvain in Belgium, intended to replace RERO's legacy proprietary library management software. It is built on Invenio, a digital library framework originally created at CERN, giving the system a research-grade, actively maintained technical foundation.$q$, $q$RERO, the organization behind the system, dates back to 1985 as a body managing IT resources for academic libraries in French-speaking Switzerland. On 29 April 2021 it was reconstituted as RERO+, a foundation of private law and public interest established by the Swiss cantons of Jura, Neuchatel, and Valais along with the city of Martigny, which now governs RERO ILS's ongoing development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$RERO ILS manages the full core workflow of a library, including document acquisitions, cataloguing, circulation and lending, and a public search and discovery interface, and it supports both standalone libraries and multi-library consortial networks operating on a shared instance.$q$, $q$The platform is multilingual by design, with interfaces available in French, German, Italian, and English, reflecting its primary deployment across public, school, and heritage libraries and library networks in Switzerland, while remaining open to adoption by libraries internationally.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea0dd7b0-e3e8-4424-afc9-75a3c6224c09', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RERO ILS is free and open source; there is no license fee to download, self-host, or modify the software, and its source code is maintained publicly for community contribution. A public test instance is available for institutions evaluating the system before committing to a migration.$q$, $q$Libraries seeking a managed deployment, data migration, or ongoing technical support typically work directly with RERO+ to arrange implementation and hosting terms, as pricing for managed services is not published and is handled on a case-by-case basis.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Automatic time tracking$q$, $q$Passively logs time spent in applications and websites across desktop and mobile without manual timers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Productivity Pulse score$q$, $q$Generates a daily productivity score based on categorized activity across apps and sites.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$FocusTime distraction blocking$q$, $q$Blocks distracting websites and apps during scheduled focus sessions to support deep work.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Goals and alerts$q$, $q$Set customizable time budgets and receive alerts when exceeding distracting-category usage or missing focus targets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Idle time detection$q$, $q$Automatically detects and excludes idle periods from productivity reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Cross-device tracking$q$, $q$Tracks activity across both desktop and mobile devices for a unified view of time use.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Timesheets add-on$q$, $q$Adds client, project, and task-level time tracking with billable rates and time rounding for consultants and agencies.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Team reporting and management$q$, $q$Team tiers add collaborative reporting and management tools for tracking productivity across a group.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Fully automatic tracking requires no manual timers or check-ins$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$FocusTime distraction blocking helps enforce deep-work sessions$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Free Lite tier available for basic automatic tracking and reporting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Timesheets add-on supports billable client work for freelancers and agencies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Remains independently operated with a long operating history since 2006$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Premium features (Focus and Timesheets) require a paid subscription$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Team pricing is per-user, which can add up for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Small company size (roughly 10-15 employees) may limit support and feature velocity$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Passive tracking requires installing and running background software on all devices$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Some advanced project/billing features are gated behind the higher Solo+ or Team+ tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$What does RescueTime do?$q$, $q$RescueTime automatically tracks how much time you spend in different applications and websites across your devices, then categorizes that activity to help you understand and improve your productivity habits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$How much does RescueTime cost?$q$, $q$RescueTime offers a free Lite tier, with paid plans starting at $7/month billed annually for Solo Focus, up to $18/month per user billed monthly for Team+ (Focus plus Timesheets).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Who founded RescueTime?$q$, $q$RescueTime was founded in 2006 by Tony Wright and Brian Fioca and is headquartered in Seattle, Washington.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Is RescueTime still an independent company?$q$, $q$Yes, as of 2026 RescueTime continues to operate as an independent, privately held company and has not been acquired by a larger parent company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$What is FocusTime in RescueTime?$q$, $q$FocusTime is a feature that blocks distracting websites and applications during scheduled focus sessions to support uninterrupted work.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Does RescueTime track time automatically or manually?$q$, $q$RescueTime tracks time automatically in the background across desktop and mobile devices, without requiring users to start or stop manual timers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$What is the Timesheets feature in RescueTime?$q$, $q$Timesheets is an add-on available on the Solo+ and Team+ tiers that adds client, project, and task-level time tracking with billable rates and time rounding.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Does RescueTime offer a free trial?$q$, $q$Yes, all paid RescueTime plans include a 14-day free trial.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Remote worker productivity tracking$q$, $q$Remote employees and freelancers use RescueTime's automatic tracking and Productivity Pulse to understand and improve how they spend their workday.$q$, $q$Remote workers and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Deep work and focus enforcement$q$, $q$Knowledge workers use FocusTime to block distracting sites and apps during scheduled deep-work sessions.$q$, $q$Knowledge workers seeking to reduce digital distraction$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Billable client time tracking$q$, $q$Consultants and agencies use the Timesheets add-on to track billable hours by client and project without manual timers.$q$, $q$Consultants and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Lite$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Automatic time tracking","Basic productivity reports","Limited goal setting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Solo Focus$q$, $q$$7/month billed annually ($84/year) or $9/month$q$, $q$monthly or annual$q$, NULL, $q$["Automatic activity tracking","FocusTime distraction blocking","Goals and alerts","Idle time detection","Personal reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Solo+$q$, $q$$12/month billed annually ($144/year) or $15/month$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Solo Focus","Timesheets: timeline view, project/task tracking","Billable rates and time rounding"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Team Focus$q$, $q$$10/month per user billed annually ($120/year) or $12/month$q$, $q$monthly or annual$q$, NULL, $q$["Focus features for teams","Team management tools","Personal and team reports"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$Team+$q$, $q$$16/month per user billed annually ($192/year) or $18/month$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Team Focus","Timesheets for teams","Billable rates and time rounding","Collaborative team reporting"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RescueTime was founded in 2006 by Tony Wright and Brian Fioca and is headquartered in Seattle, Washington. The company built one of the earliest automatic time-tracking tools, designed to passively log how users spend time across applications and websites without requiring manual timers.$q$, $q$As of 2026, RescueTime remains an independently operated, privately held company rather than part of a larger parent company, running as a small, distributed team backed historically by Y Combinator, True Ventures, and Lowercase Capital.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$RescueTime's core function is automatic, passive tracking of time spent in desktop and mobile applications and websites, which it categorizes by productivity level to generate a daily Productivity Pulse score and detailed usage reports. Its FocusTime feature can actively block distracting sites and apps during scheduled focus sessions.$q$, $q$Additional capabilities include customizable goals and alerts, idle-time detection, and cross-device tracking. The Timesheets add-on, available on Solo+ and Team+ tiers, layers in client, project, and task-level time tracking with billable rates and time rounding for consultants and agencies.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60589788-e511-45e9-b6b4-e65384870261', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RescueTime offers a free Lite tier alongside four paid plans split across Solo and Team tiers and Focus versus Focus-plus-Timesheets feature sets. Solo Focus is $7/month billed annually ($84/year) or $9/month billed monthly; Solo+ (adding Timesheets) is $12/month billed annually ($144/year) or $15/month billed monthly.$q$, $q$Team Focus is $10/month per user billed annually ($120/year per user) or $12/month billed monthly; Team+ is $16/month per user billed annually ($192/year per user) or $18/month billed monthly. All paid plans include a 14-day free trial, and invoice billing is available for teams of 100 or more users.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Voice cloning$q$, $q$Creates a synthetic voice clone from a sample of human speech that can generate new speech from arbitrary text.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Real-time streaming TTS$q$, $q$Low-latency text-to-speech (around 75ms on Chatterbox Turbo) suited to live conversational voice applications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Deepfake detection (Detect)$q$, $q$Analyzes audio, video, and image content to identify likely AI-generated or manipulated deepfakes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Watermarking and verification (Verify)$q$, $q$Embeds and detects watermarks in AI-generated audio for provenance and authenticity tracking.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Identity search$q$, $q$Searches for a voice's identity match against known voice profiles for verification purposes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Full API access$q$, $q$Complete programmatic access to voice cloning, synthesis, detection, and verification from the start of a Flex account.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Custom model training$q$, $q$Enterprise customers can access custom model training and tuning for specialized use cases.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$On-premises deployment$q$, $q$Enterprise tier offers an on-premises deployment option for organizations with strict data requirements.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Consumption-based pricing with no minimum spend to start on the Flex plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Credits never expire under the Flex plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Combines voice generation with deepfake detection and watermarking in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Low-latency real-time streaming synthesis suitable for live conversational use$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Enterprise tier offers on-premises deployment for sensitive data requirements$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Granular per-feature usage pricing can make total costs harder to predict upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Enterprise pricing is not public and starts at a high four-figure monthly commitment$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Small team size (about 39 employees) relative to larger TTS competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Voice clone hosting fees ($2-$5/month each) add up for accounts managing many clones$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Team seats are billed separately at $20/month per user on top of usage costs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$What does Resemble AI do?$q$, $q$Resemble AI is a generative voice platform that clones voices from speech samples and generates new synthetic speech, alongside deepfake detection and content watermarking tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$How does Resemble AI pricing work?$q$, $q$Resemble AI uses a consumption-based Flex plan with no upfront cost, billing about $0.0005 per second of synthesized speech, $2-$5/month per hosted voice clone, and $20/month per team seat, plus separate per-second rates for deepfake detection.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$When was Resemble AI founded?$q$, $q$Resemble AI was founded in 2019 and is headquartered in Santa Clara, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$What is Resemble AI's Detect product?$q$, $q$Detect is Resemble AI's deepfake detection product that analyzes audio, video, and image content to identify likely AI-generated or manipulated media.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$What is Resemble AI's Verify product?$q$, $q$Verify is Resemble AI's watermarking and content-provenance product, used to embed and detect watermarks in AI-generated audio.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Does Resemble AI support real-time voice synthesis?$q$, $q$Yes, Resemble AI offers real-time streaming text-to-speech with latency around 75 milliseconds on its Chatterbox Turbo model.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$How much funding has Resemble AI raised?$q$, $q$Resemble AI has raised approximately $25 million in total funding across five rounds, including an $8 million Series A in 2023.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Does Resemble AI offer an Enterprise plan?$q$, $q$Yes, Resemble AI offers a custom-priced Enterprise plan with volume discounts, elevated concurrency limits, SLAs, custom model training, SSO/SAML, and on-premises deployment.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Media dubbing and localization$q$, $q$Media and entertainment companies use Resemble AI to generate localized voiceovers and dubbing in cloned voices across languages.$q$, $q$Media and entertainment production teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Conversational voice agents$q$, $q$Customer experience teams use Resemble AI's real-time streaming synthesis to power low-latency conversational IVR and voice agents.$q$, $q$Customer experience and IVR engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Deepfake and content moderation$q$, $q$Trust-and-safety teams use Resemble AI's Detect and Verify products to identify AI-generated or manipulated audio and video content.$q$, $q$Trust-and-safety and content-moderation teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Flex$q$, $q$$0 to start (pay-as-you-go)$q$, $q$usage-based$q$, NULL, $q$["Credits never expire","Full API access from day one","Synthesis at about $0.0005/second","Voice clone hosting at $2-$5/month each","Team seats at $20/month per user","Access to Detect and Verify"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Enterprise$q$, $q$Custom (high four-figures monthly commitment and up)$q$, $q$annual contract$q$, NULL, $q$["Volume discounts for committed spend","Elevated concurrency limits","Enterprise-grade support SLAs","Custom model training and tuning","SSO/SAML authentication","On-premises deployment option"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Resemble AI, founded in 2019 and headquartered in Santa Clara, California, builds generative voice technology centered on voice cloning: creating a synthetic voice from a sample of human speech that can then read arbitrary text aloud. The company has raised approximately $25 million in funding across five rounds, including an $8 million Series A in 2023 led by Javelin Venture Partners.$q$, $q$Since 2024, Resemble AI has expanded beyond core text-to-speech into real-time streaming voice synthesis, with its Chatterbox Turbo model achieving around 75ms latency, alongside two content-integrity products: Detect, for identifying AI-generated deepfake audio, video, and images, and Verify, for watermarking and provenance tracking of AI-generated content.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core capability is voice cloning and text-to-speech synthesis from a short sample of human speech, paired with real-time streaming synthesis for low-latency conversational applications. Its Detect product analyzes audio, video, and image content to flag likely AI-generated or manipulated deepfakes, while Verify provides watermarking and identity-search tools for content provenance.$q$, $q$Resemble AI offers full API access alongside a web UI, letting developers integrate voice cloning and synthesis directly into applications such as IVR systems, games, dubbing pipelines, and content-moderation tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Resemble AI's 2026 pricing is fully consumption-based under its Flex plan, which requires no upfront payment, offers credits that never expire, and grants full API access from day one. Synthesis is billed at roughly $0.0005 per second of generated speech, each hosted voice clone costs about $2-$5 per month, and additional team seats are $20 per month per user.$q$, $q$Detection and verification features are billed separately and granularly: audio and image deepfake detection run about $0.04 per second, video detection about $0.07 per second, and 'intelligence' analysis about $0.03 per second across audio, video, and image; watermarking and identity search are billed at fractions of a cent per operation. Enterprise customers negotiate custom volume pricing, typically starting in the high four-figures per month for committed spend, in exchange for elevated limits, SLAs, and dedicated support.$q$]::text[], 2);
