-- ── Replit ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Replit is a browser-based coding and AI app-building platform that lets developers write, run, deploy, and collaborate on software from any device, powered by its AI coding agent.$q$, short_description),
  pricing_model = COALESCE($q$freemium with usage credits (subscription plus consumption)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Starter plan); Core plan from $20/month billed annually$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$201-500$q$, company_size),
  headquarters = COALESCE($q$Foster City, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Replit Review 2026: Pricing, AI Agent, and Features Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$A 2026 look at Replit's pricing tiers, AI Agent capabilities, and how the browser-based coding platform compares for building and deploying apps.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Replit is a cloud-based software development platform, founded in 2016 by Amjad Masad, Haya Odeh, and Faris Masad, that lets anyone write, run, and deploy code entirely in the browser, and has increasingly repositioned itself around an AI coding agent that can build and ship full applications from natural-language prompts. The company is headquartered at 1001 East Hillsdale Boulevard in Foster City, California, having relocated there from San Francisco in 2024, and reports several hundred employees. Replit has raised roughly $922 million in total funding from investors including Andreessen Horowitz, Craft Ventures, and Reach Capital; in March 2026 it closed a $400 million Series D led by Georgian at a $9 billion valuation, roughly triple its valuation six months earlier, and the company has stated it is targeting $1 billion in annualized run-rate revenue by the end of 2026. Replit's product spans a cloud IDE with instant environments for dozens of languages, real-time multiplayer collaboration, a built-in database and hosting layer for full-stack apps, and Replit Agent, its AI system that can scaffold, write, debug, and deploy software from a plain-language description. As of 2026 Replit offers four tiers: a free Starter plan with limited daily Agent credits and one publishable app; Core at $20/month billed annually (or $25 month-to-month) with $25 in monthly usage credits, up to five collaborators, and the ability to run two AI agents in parallel; Pro, which replaced the former Teams plan in February 2026, at $95/month billed annually (or $100 month-to-month) with $100 in monthly credits, up to 15 collaborators, 50 viewers, ten parallel agents, access to the most capable AI models, and 28-day database rollbacks; and a custom-priced Enterprise plan with SSO/SAML, single-tenant environments, VPC peering, and dedicated support for regulated industries. Because usage credits rather than flat subscription fees drive most of the real cost, actual monthly bills can exceed the advertised plan price once AI Agent usage surpasses the included credit allotment. Replit is used by students learning to code, hobbyists building side projects, and increasingly by non-technical founders and enterprise teams using the Agent to generate production-ready web and mobile applications without writing code by hand; the company has said users from roughly 85% of the Fortune 500 have built something on the platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c628f71b-c0ff-42aa-87ea-a09dfbd28490';

