-- ── Repurpose.io ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Repurpose.io is an automated content repurposing and distribution platform that resizes and republishes video and audio content across TikTok, Instagram, YouTube Shorts, Facebook, and other social platforms.$q$, short_description),
  pricing_model = COALESCE($q$tiered subscription$q$, pricing_model),
  starting_price = COALESCE($q$$35/month (Starter plan), or $349/year billed annually$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$1-10$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Repurpose.io Review 2026: Pricing, Features, and Automation$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Repurpose.io's pricing, plans, and automated workflows help creators repurpose video and podcast content across social platforms in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Repurpose.io is a content automation platform founded in November 2016 by CEO Hani Mourra, who previously built SimpleSocialPress.com, and is headquartered in Austin, Texas, operating with a lean team of roughly 9 to 11 employees. The platform's core function is 'fire-and-forget' content repurposing: it automatically pulls new video, Reels, Shorts, Stories, or podcast episodes from a source platform, resizes and reformats them for each destination, removes watermarks, and publishes them across more than 15 channels including TikTok, YouTube Shorts, Instagram, Facebook, Pinterest, LinkedIn, X, Amazon, BlueSky, and Twitch, without requiring the creator to manually re-upload or reformat anything after the initial workflow is set up. The company markets itself as an official platform partner of Meta, YouTube, TikTok, Snapchat, and Amazon, arguing that routing automation through approved API integrations avoids the account-flagging risk associated with unofficial scraping or browser-automation tools, and highlights a decade-long partnership history along with a Stories-repurposing capability it says is not matched by direct competitors. As of 2026, Repurpose.io is priced on three monthly tiers: Starter at $35/month (or $349/year on annual billing, roughly a 17% discount) supporting up to 3 connected accounts per social network and 5,000 published videos per month, aimed at solo creators and small business owners; Pro at $79/month ($790/year) raising the account limit to 10 per network with unlimited published videos, aimed at growing teams and creators managing multiple brands; and Agency at $179/month ($1,790/year) supporting up to 25 accounts per network with unlimited publishing, aimed at agencies managing multiple clients. All plans include a 14-day free trial, and new users can test the platform with 10 free video publishes before subscribing. Repurpose.io differentiates itself from general social media schedulers by focusing specifically on automated cross-platform redistribution of existing long-form or short-form content rather than original content creation or generic post scheduling, making it popular with podcasters, YouTubers, TikTok creators, and course creators who want to multiply the reach of content they have already produced without manually re-editing and re-uploading it to every platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f07f9c22-d47c-4952-97ad-64f962870184';

