-- ── Reputation ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Reputation (Reputation.com) is an enterprise reputation and experience management platform that helps multi-location businesses monitor reviews, surveys, and search/AI visibility across locations.$q$, short_description),
  pricing_model = COALESCE($q$custom enterprise subscription$q$, pricing_model),
  starting_price = COALESCE($q$From approximately $80/month entry point, though most deployments require custom enterprise quotes$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$501-1000$q$, company_size),
  headquarters = COALESCE($q$San Ramon, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Reputation.com Review 2026: Pricing, Features, and Enterprise Use Cases$q$, seo_title),
  seo_meta_description = COALESCE($q$An overview of Reputation.com's enterprise reputation management platform, pricing structure, and key features for multi-location businesses in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Reputation, commonly known as Reputation.com, is an enterprise reputation and customer experience management platform founded in 2006 by Michael Fertik and Brian Kelley. The company originally operated as ReputationDefender, focused on consumer online-reputation services, before pivoting toward enterprise B2B reputation management around 2011. It is headquartered at 6111 Bollinger Canyon Road, Suite 500, San Ramon, California, and employs roughly 693 people as of 2026. The company has raised approximately $325.3 million in total funding across multiple rounds from investors including Kleiner Perkins, Bessemer Venture Partners, and Marlin Equity Partners, with its most recent disclosed valuation at approximately $730 million post-money following a $150 million minority investment led by Marlin Equity Partners in January 2022, advised by Goldman Sachs. Reputation.com markets itself as an AI-native reputation management platform built to help multi-location businesses be found, trusted, and chosen across traditional search engines and newer AI-driven answer engines, and its ideal customer profile centers on enterprise organizations with 50 to 500 employees, $10 million or more in annual recurring revenue, and 10 or more physical locations, spanning industries like healthcare systems, automotive dealership groups, property management firms, restaurant chains, and retail networks. The core platform aggregates and analyzes online reviews, survey feedback, social listening, and local business listing data across every location a brand operates, and provides tools for responding to reviews at scale, benchmarking location-level reputation against competitors, and increasingly, tracking how a brand appears within AI-generated search and chatbot answers. Pricing is not publicly tiered; while some sources cite an entry point around $80 per month for a Core-level offering, real-world enterprise deployments for organizations managing dozens or hundreds of locations typically range from several thousand to over $20,000 per month depending on the number of locations and brands managed, the specific modules licensed (reviews, surveys, social, listings, AI visibility), data volume, level of customization, number of user seats, and contract length. There is no publicly available free trial; prospective customers must go through a sales-led demo and custom quote process. Reputation.com is used primarily by multi-location enterprises — such as auto dealer groups, healthcare systems, and multi-unit retail or restaurant brands — that need centralized visibility and control over their online reputation and customer feedback across dozens or hundreds of individual locations, rather than by small businesses or single-location operators.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '69e9043e-430d-4fc5-97c8-fc58de34946f';

