-- ── Request Tracker ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Request Tracker (RT) is an open-source ticketing and workflow management system built by Best Practical Solutions, used by IT, support, and operations teams to track tickets, assets, and SLAs.$q$, short_description),
  pricing_model = COALESCE($q$open source (self-hosted, free) with paid Cloud RT and support/services options$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, open source); hosted Cloud RT and support plans priced separately by Best Practical Solutions$q$, starting_price),
  founded_year = COALESCE(1996, founded_year),
  company_size = COALESCE($q$1-10$q$, company_size),
  headquarters = COALESCE($q$Somerville, Massachusetts, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and 35+ interface languages via community translations$q$]::text[],
  seo_title = COALESCE($q$Request Tracker (RT) Review 2026: Open-Source Ticketing Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how Request Tracker (RT), Best Practical Solutions' open-source ticketing system, works, what it costs to self-host or run in the cloud, and its key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Request Tracker, widely known as RT, is an open-source ticketing and workflow management system originally released in 1996 by Jesse Vincent, who began developing it as a student at Wesleyan University working on the school's computing help desk, before founding Best Practical Solutions LLC to develop, distribute, and support the software commercially. Best Practical Solutions is a small company headquartered in Somerville, Massachusetts, with roughly 9 to 11 employees, and reported revenue in the range of about $12 million. RT is distributed under the GNU General Public License and remains free and open source to self-host, with source code maintained publicly on GitHub; Best Practical also offers a hosted Cloud RT service and paid training, consulting, and support packages for organizations that prefer not to self-manage the software. The platform is designed for IT help desks, customer support teams, and internal operations groups that need to track and route incoming requests as structured tickets, and after nearly three decades of development it includes email integration for creating and updating tickets by email, a visual Lifecycle builder for customizing ticket workflows and states, an automation engine called Scrips and Actions for triggering rules-based responses, a built-in knowledge base (Articles) for FAQs and canned responses, asset management for tracking associated equipment or configuration items, SLA management with business-hours awareness, role-based security and granular permissions, a REST v2 API, Zapier integration, and a multi-language interface supporting more than 35 languages. RT also has a specialized variant, RT for Incident Response (RTIR), aimed at security teams handling incident tickets. Because RT is free to download and self-host under an open-source license, third-party pricing aggregators often cite tiered per-user monthly pricing (for example, figures around $25 to $105 per user per month across Starter, Business, Growth, and Enterprise tiers) that reflect Best Practical's hosted Cloud RT and support offerings rather than a cost required to use the core open-source software itself. RT is popular in academic institutions, government agencies, and IT organizations that value self-hosting, data control, and the absence of vendor lock-in over the convenience of a fully managed SaaS helpdesk, and it has more than 400 freely available community-built extensions that expand its functionality beyond the base install.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c74c6d31-a2de-408d-9658-1ce6cd0f1ff3';

