-- ── RERO ILS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RERO ILS is a free, open-source integrated library system built on the CERN-developed Invenio framework, used mainly by public, school, and heritage libraries and library networks in Switzerland.$q$, short_description),
  pricing_model = COALESCE($q$open source (free), with implementation/hosting support available through RERO+$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); implementation and hosting support terms available on request from RERO+$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Martigny, Valais, Switzerland$q$, headquarters),
  languages = ARRAY[$q$French$q$, $q$German$q$, $q$Italian$q$, $q$English$q$]::text[],
  seo_title = COALESCE($q$RERO ILS Review: Open-Source Library System Features and Overview$q$, seo_title),
  seo_meta_description = COALESCE($q$An overview of RERO ILS, the open-source integrated library system developed in Switzerland on the Invenio framework, its features, and who uses it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RERO ILS is a free, open-source integrated library system (ILS) developed beginning in 2017 by RERO, in collaboration with the Catholic University of Louvain (UCLouvain) in Belgium, as a next-generation replacement for RERO's legacy proprietary library software. The system is built on Invenio, a digital library framework originally developed at CERN, giving RERO ILS a research-grade technical foundation. RERO itself traces back to 1985, when it was created to manage the emerging IT resources of academic libraries in French-speaking Switzerland; on 29 April 2021, RERO was reconstituted as RERO+, a foundation of private law and public interest formally established by the Swiss cantons of Jura, Neuchatel, and Valais along with the city of Martigny, which now governs and develops RERO ILS. RERO ILS reached its first major stable release (v1.0.0) at the end of 2020, and its first real-world production library instance went live in June 2021, after several years of active development. The platform is designed to manage the full range of core library operations, including document acquisition, cataloguing, circulation and lending, and public-facing search and discovery interfaces, and it supports both independent libraries and consortial library networks operating under a shared system. RERO ILS is multilingual by design, with its interface available in French, German, Italian, and English, reflecting its primary user base of public, school, and heritage libraries and library networks across Switzerland, alongside international interest from other libraries seeking an open-source alternative to proprietary integrated library systems like Ex Libris Alma or SirsiDynix. Because RERO ILS is open source and collaboratively developed, there is no license fee to use or self-host the software; libraries and institutions that want a fully managed deployment, migration assistance, or ongoing technical support typically arrange terms directly with RERO+ or through community contribution channels, and organizations can explore the platform via a public test instance and contribute to its development through its GitHub repository and community chat channels. As a niche, sector-specific library system rather than a mainstream commercial SaaS product, RERO ILS is primarily relevant to library administrators, systems librarians, and consortium IT staff evaluating open-source alternatives to proprietary ILS platforms, rather than to general business software buyers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ea0dd7b0-e3e8-4424-afc9-75a3c6224c09';

