-- ── RescueTime ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RescueTime is an automatic time-tracking and focus app that monitors app and website usage to help individuals and teams understand and improve their productivity habits.$q$, short_description),
  pricing_model = COALESCE($q$freemium subscription (Solo and Team tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Lite); paid Solo Focus plan from $7/month billed annually ($84/year)$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$1-10$q$, company_size),
  headquarters = COALESCE($q$Seattle, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$RescueTime Review 2026: Pricing, Plans, and Focus Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how RescueTime's automatic time tracking, focus tools, and 2026 pricing plans compare for individuals and teams trying to improve productivity.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RescueTime is an automatic time-tracking and productivity application founded in 2006 by Tony Wright and Brian Fioca, headquartered in Seattle, Washington, and backed early on by Y Combinator, True Ventures, and Lowercase Capital. As of 2026, the company remains an independent, privately held business rather than being owned by a larger acquirer, and operates as a lean, distributed team of roughly 10 to 15 employees spread across the United States. RescueTime's core product runs in the background on a user's computer and mobile devices, automatically logging time spent in applications and websites without requiring manual timers, then categorizing that activity by productivity level to generate reports, trends, and a daily 'Productivity Pulse' score. Its differentiating features beyond passive tracking include FocusTime, which blocks distracting websites and apps during designated focus sessions; customizable goals and alerts that notify users when they exceed time budgets on distracting categories or fall short of focus targets; idle-time detection; and cross-device activity tracking spanning desktop and mobile. In 2025 and into 2026, RescueTime restructured its pricing around two feature tracks, Focus and Timesheets, offered in both individual (Solo) and team configurations. Solo Focus costs $7/month billed annually ($84/year) or $9/month billed monthly, and includes automatic tracking, distraction blocking, goals and alerts, idle-time detection, and personal reports. Solo+ adds Timesheets functionality — including a timeline view, client/project/task tracking, billable rates, and time rounding — for $12/month billed annually ($144/year) or $15/month billed monthly. Team Focus is priced per user at $10/month billed annually ($120/year per user) or $12/month billed monthly, and Team+ (Focus plus Timesheets) is $16/month billed annually ($192/year per user) or $18/month billed monthly, with both team tiers adding collaborative team-management and reporting tools. A free-forever Lite tier remains available with core automatic tracking and reporting but without the premium focus and timesheet features. All paid plans include a 14-day free trial, invoice billing is available for teams of 100 or more users, and the company charges no sales tax or VAT. RescueTime is widely used by remote workers, freelancers, and small teams who want passive, low-effort insight into how their time is actually spent across apps and websites, as well as by consultants and agencies that use the Timesheets tier to track billable client work without manually starting and stopping timers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '60589788-e511-45e9-b6b4-e65384870261';

